import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Resolve the real paths to avoid symlink tricks
        dir_real = os.path.realpath(dir_path)
        file_path = os.path.join(dir_path, filename)
        file_real = os.path.realpath(file_path)

        # Ensure the resolved file path is inside the resolved directory
        if not file_real.startswith(dir_real + os.sep) and file_real != dir_real:
            return ""

        # Read and return file content
        with open(file_real, 'r') as f:
            return f.read()
    except Exception:
        return ""

