        os.makedirs(dest_path, exist_ok=True)
        dest_path = os.path.realpath(dest_path)

        with tarfile.open(tar_path, 'r:*') as tar:
            # Use the filter argument if available (Python 3.12+)
            if hasattr(tarfile, 'data_filter'):
                tar.extractall(path=dest_path, filter='data')
            else:
                # Manual safe extraction for older Python versions
                for member in tar.getmembers():
                    # Skip members with absolute paths or path traversal
                    if member.name.startswith('/') or '..' in member.name.split('/'):
                        continue
                    # Resolve the full destination path
                    target_path = os.path.realpath(os.path.join(dest_path, member.name))
                    # Ensure the target path is within dest_path
                    if not target_path.startswith(dest_path + os.sep) and target_path != dest_path:
                        continue
                    if member.isdir():
                        os.makedirs(target_path, exist_ok=True)
                    elif member.isfile():
                        os.makedirs(os.path.dirname(target_path), exist_ok=True)
                        with tar.extractfile(member) as source, open(target_path, 'wb') as target:
                            target.write(source.read())
                    # Ignore other types (symlinks, devices, etc.) for safety
        return True
    except Exception:
        return False

