) -> Dict[str, str]:
    mapping = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }
    if not isinstance(info_type, str) or info_type not in mapping:
        return header
    if not isinstance(info_content, str):
        return header
    # Prevent CRLF injection
